#include <stdio.h>
#include <stdlib.h>

typedef struct {int start; int idx;} Pair;

int cmpPair(const void *a, const void *b) {
    const Pair *pa = (const Pair *)a;
    const Pair *pb = (const Pair *)b;
    return (pa->start < pb->start) ? -1 : (pa->start > pb->start);
}

int lower_bound(Pair *arr, int n, int target) {
    int l = 0, r = n; // [l, r)
    while (l < r) {
        int m = l + (r - l) / 2;
        if (arr[m].start >= target) r = m; else l = m + 1;
    }
    return l; // may be n
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *starts = (int *)malloc(N * sizeof(int));
        int *ends   = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) {
            scanf("%d %d", &starts[i], &ends[i]);
        }
        Pair *arr = (Pair *)malloc(N * sizeof(Pair));
        for (int i = 0; i < N; ++i) {
            arr[i].start = starts[i];
            arr[i].idx = i;
        }
        qsort(arr, N, sizeof(Pair), cmpPair);
        for (int i = 0; i < N; ++i) {
            int pos = lower_bound(arr, N, ends[i]);
            if (pos == N) printf("-1");
            else printf("%d", arr[pos].idx);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
        free(starts); free(ends); free(arr);
    }
    return 0;
}

