const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = Number(data[idx++]);
let out = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(data[idx++]);
  const starts = new Array(N);
  const ends = new Array(N);
  for (let i = 0; i < N; i++) {
    starts[i] = Number(data[idx++]);
    ends[i] = Number(data[idx++]);
  }
  const startPairs = starts.map((s, i) => [s, i]);
  startPairs.sort((a, b) => a[0] - b[0]);
  const sortedStarts = startPairs.map(p => p[0]);
  const sortedIdx = startPairs.map(p => p[1]);
  const res = new Array(N);
  for (let i = 0; i < N; i++) {
    // binary search lower bound
    let l = 0, r = N;
    while (l < r) {
      const m = (l + r) >> 1;
      if (sortedStarts[m] >= ends[i]) r = m; else l = m + 1;
    }
    if (l === N) res[i] = -1; else res[i] = sortedIdx[l];
  }
  out.push(res.join(' '));
}
